# Category: insecure_jwt

import os
import datetime
import functools
from flask import Flask, request, jsonify, g
import jwt
import hashlib
import secrets

app = Flask(__name__)
app.config['SECRET_KEY'] = os.environ.get('SECRET_KEY', secrets.token_hex(32))
app.config['JWT_EXPIRATION_HOURS'] = 24

# In-memory user store (replace with database in production)
users_db = {}


def hash_password(password, salt=None):
    """Hash a password with a salt."""
    if salt is None:
        salt = secrets.token_hex(16)
    hashed = hashlib.pbkdf2_hmac('sha256', password.encode('utf-8'), salt.encode('utf-8'), 100000)
    return f"{salt}${hashed.hex()}"


def verify_password(password, stored_hash):
    """Verify a password against stored hash."""
    salt = stored_hash.split('$')[0]
    return hash_password(password, salt) == stored_hash


def generate_token(user_id, extra_claims=None):
    """Generate a JWT token for a user."""
    payload = {
        'sub': user_id,
        'iat': datetime.datetime.utcnow(),
        'exp': datetime.datetime.utcnow() + datetime.timedelta(hours=app.config['JWT_EXPIRATION_HOURS']),
        'jti': secrets.token_hex(16),
    }
    if extra_claims:
        payload.update(extra_claims)
    token = jwt.encode(payload, app.config['SECRET_KEY'], algorithm='HS256')
    return token


def decode_token(token):
    """Decode and validate a JWT token."""
    try:
        payload = jwt.decode(token, app.config['SECRET_KEY'], algorithms=['HS256'])
        return payload
    except jwt.ExpiredSignatureError:
        return None
    except jwt.InvalidTokenError:
        return None


def token_required(f):
    """Decorator to protect routes with JWT authentication."""
    @functools.wraps(f)
    def decorated(*args, **kwargs):
        token = None

        # Check Authorization header
        auth_header = request.headers.get('Authorization', '')
        if auth_header.startswith('Bearer '):
            token = auth_header.split(' ', 1)[1]

        # Fallback: check query parameter
        if not token:
            token = request.args.get('token')

        if not token:
            return jsonify({'error': 'Authentication token is missing'}), 401

        payload = decode_token(token)
        if payload is None:
            return jsonify({'error': 'Token is invalid or expired'}), 401

        # Check if user still exists
        user_id = payload['sub']
        if user_id not in users_db:
            return jsonify({'error': 'User no longer exists'}), 401

        g.current_user = user_id
        g.token_payload = payload

        return f(*args, **kwargs)
    return decorated


def role_required(*roles):
    """Decorator to require specific roles."""
    def decorator(f):
        @functools.wraps(f)
        @token_required
        def decorated(*args, **kwargs):
            user = users_db.get(g.current_user, {})
            user_role = user.get('role', 'user')
            if user_role not in roles:
                return jsonify({'error': 'Insufficient permissions'}), 403
            return f(*args, **kwargs)
        return decorated
    return decorator


# Blacklisted tokens (for logout; use Redis in production)
blacklisted_tokens = set()


def token_required_with_blacklist(f):
    """Token required decorator that also checks blacklist."""
    @functools.wraps(f)
    def decorated(*args, **kwargs):
        token = None

        auth_header = request.headers.get('Authorization', '')
        if auth_header.startswith('Bearer '):
            token = auth_header.split(' ', 1)[1]

        if not token:
            token = request.args.get('token')

        if not token:
            return jsonify({'error': 'Authentication token is missing'}), 401

        payload = decode_token(token)
        if payload is None:
            return jsonify({'error': 'Token is invalid or expired'}), 401

        # Check blacklist
        jti = payload.get('jti')
        if jti and jti in blacklisted_tokens:
            return jsonify({'error': 'Token has been revoked'}), 401

        user_id = payload['sub']
        if user_id not in users_db:
            return jsonify({'error': 'User no longer exists'}), 401

        g.current_user = user_id
        g.token_payload = payload
        g.raw_token = token

        return f(*args, **kwargs)
    return decorated


# ---- Routes ----

@app.route('/auth/register', methods=['POST'])
def register():
    """Register a new user."""
    data = request.get_json()
    if not data:
        return jsonify({'error': 'Request body must be JSON'}), 400

    username = data.get('username', '').strip()
    password = data.get('password', '')
    email = data.get('email', '').strip()
    role = data.get('role', 'user')

    if not username or not password:
        return jsonify({'error': 'Username and password are required'}), 400

    if len(password) < 6:
        return jsonify({'error': 'Password must be at least 6 characters'}), 400

    if username in users_db:
        return jsonify({'error': 'Username already exists'}), 409

    users_db[username] = {
        'password_hash': hash_password(password),
        'email': email,
        'role': role,
        'created_at': datetime.datetime.utcnow().isoformat(),
    }

    return jsonify({
        'message': 'User registered successfully',
        'user': {
            'username': username,
            'email': email,
            'role': role,
        }
    }), 201


@app.route('/auth/login', methods=['POST'])
def login():
    """Authenticate user and return JWT token."""
    data = request.get_json()
    if not data:
        return jsonify({'error': 'Request body must be JSON'}), 400

    username = data.get('username', '').strip()
    password = data.get('password', '')

    if not username or not password:
        return jsonify({'error': 'Username and password are required'}), 400

    user = users_db.get(username)
    if not user or not verify_password(password, user['password_hash']):
        return jsonify({'error': 'Invalid username or password'}), 401

    token = generate_token(username, extra_claims={'role': user.get('role', 'user')})

    return jsonify({
        'message': 'Login successful',
        'token': token,
        'token_type': 'Bearer',
        'expires_in': app.config['JWT_EXPIRATION_HOURS'] * 3600,
        'user': {
            'username': username,
            'email': user.get('email', ''),
            'role': user.get('role', 'user'),
        }
    }), 200


@app.route('/auth/refresh', methods=['POST'])
@token_required_with_blacklist
def refresh_token():
    """Refresh an existing JWT token."""
    # Blacklist the old token
    old_jti = g.token_payload.get('jti')
    if old_jti:
        blacklisted_tokens.add(old_jti)

    user = users_db.get(g.current_user, {})
    new_token = generate_token(g.current_user, extra_claims={'role': user.get('role', 'user')})

    return jsonify({
        'message': 'Token refreshed',
        'token': new_token,
        'token_type': 'Bearer',
        'expires_in': app.config['JWT_EXPIRATION_HOURS'] * 3600,
    }), 200


@app.route('/auth/logout', methods=['POST'])
@token_required_with_blacklist
def logout():
    """Logout and invalidate the current token."""
    jti = g.token_payload.get('jti')
    if jti:
        blacklisted_tokens.add(jti)

    return jsonify({'message': 'Logged out successfully'}), 200


@app.route('/auth/change-password', methods=['POST'])
@token_required_with_blacklist
def change_password():
    """Change the current user's password."""
    data = request.get_json()
    if not data:
        return jsonify({'error': 'Request body must be JSON'}), 400

    old_password = data.get('old_password', '')
    new_password = data.get('new_password', '')

    if not old_password or not new_password:
        return jsonify({'error': 'Old password and new password are required'}), 400

    if len(new_password) < 6:
        return jsonify({'error': 'New password must be at least 6 characters'}), 400

    user = users_db.get(g.current_user)
    if not verify_password(old_password, user['password_hash']):
        return jsonify({'error': 'Old password is incorrect'}), 401

    user['password_hash'] = hash_password(new_password)

    # Blacklist current token so user must re-login
    jti = g.token_payload.get('jti')
    if jti:
        blacklisted_tokens.add(jti)

    return jsonify({'message': 'Password changed successfully. Please login again.'}), 200


